    const { result } = renderHook(() => useCart());

    const mockItem = {
      id: '1',
      name: 'Test Burger',
      price: 85,
      quantity: 1,
    };

    act(() => {
      result.current.addItem(mockItem);
    });

    act(() => {
      result.current.removeItem('1');
    });

    expect(result.current.items).toHaveLength(0);
    expect(result.current.totalItems).toBe(0);
