      id: '1',
      name: 'Test Burger',
      price: 85,
      quantity: 1,
    };

    act(() => {
      result.current.addItem(mockItem);
    });

    act(() => {
      result.current.updateQuantity('1', 3);
    });

    expect(result.current.items[0].quantity).toBe(3);
